import { BrowserRouter, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { useState, createContext, useContext } from "react";
import classes from "./app.module.css";

import Home from "../components/pages/Home";
import Login from "../components/pages/Login";
import CalorieCalc from "../components/pages/CalorieCalc";
import Profile from "../components/pages/Profile";
import NavBar from "../components/navBar/NavBar";
import NotFound from "../components/pages/NotFound";

// Context for Authentication
const AuthContext = createContext();

const pages = [
  { name: "מחשבון קלוריות", path: "/CalorieCalc" },
  { name: "פרופיל", path: "/profile" },
  { name: "בית", path: "/home" },
];

// Hook to use auth anywhere
const useAuth = () => useContext(AuthContext);

// Wrapper for protected routes
const RequireAuth = ({ children, allowGuest = false }) => {
  const location = useLocation();
  const { isLoggedIn } = useAuth();

  if (!isLoggedIn && !allowGuest) {
    return <Navigate to="/" state={{ from: location }} replace />;
  }

  return children;
};

export default function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);

  const handleLogin = (user) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
  };

  const authContextValue = {
    isLoggedIn,
    currentUser,
    handleLogin,
    handleLogout,
  };

  return (
    <AuthContext.Provider value={authContextValue}>
      <section className={classes.app}>
        <BrowserRouter>
          <Routes>
            <Route path="/" element={<Login onLoginSuccess={handleLogin} />} />

            <Route
              path="/home"
              element={
                <RequireAuth allowGuest>
                  <>
                    <NavBar pages={pages} auth={authContextValue} />
                    <Home />
                  </>
                </RequireAuth>
              }
            />

            <Route
              path="/CalorieCalc"
              element={
                <RequireAuth>
                  <>
                    <NavBar pages={pages} auth={authContextValue} />
                    <CalorieCalc />
                  </>
                </RequireAuth>
              }
            />

            <Route
              path="/profile"
              element={
                <RequireAuth>
                  <>
                    <NavBar pages={pages} auth={authContextValue} />
                    <Profile />
                  </>
                </RequireAuth>
              }
            />

            <Route path="*" element={<NotFound />} />
          </Routes>
        </BrowserRouter>
      </section>
    </AuthContext.Provider>
  );
}
